private m_parentNode: Node = null;

private m_isEnd: boolean = true;
public get IsEnd(): boolean
{
    return this.m_isEnd;
}
public set IsEnd( check: boolean )
{
    this.m_isEnd = check;
}
private m_isShowEnd: boolean = true;
private m_isShowAward: boolean = false;

private m_eventCb: ( name: string, strValue: string, animName: string ) => void = null;
private m_showValueCb: ( value: number ) => number = null;
private m_cancelCb: () => void = null;
private m_completeCb: () => void = null;

private m_lvl: number = 0;
private m_nowLvl: number = 0;

private m_win: number = 0;
private m_showWin: number = 0;

private m_step: number = 0;

private m_isShowingExtraEnd: boolean = false;

private _isRegistered = false;

private m_lastShownValue: number = NaN;

update( dt )
{
    if ( this.m_isShowAward )
    {
        this.m_showWin += this.m_step * dt;
        if ( this.m_showWin >= this.m_win )
        {
            this.m_showWin = this.m_win;
            this.m_isShowAward = false;
        }

        const showValue = tools.strip( this.m_showValueCb ? this.m_showValueCb( this.m_showWin ) : this.m_showWin );
        if ( showValue !== this.m_lastShownValue )
        {
            this.m_lastShownValue = showValue;
            this.m_winLabel.string = tools.FormatNumberThousands(
                showValue,
                tools.FORMAT_NUMBER_TYPE.PERMANENT_DOT
            );
        }
    }
}

protected onEnable(): void
{
    if ( !this._isRegistered )
    {
        eventManager.Register( SHOW_AWARD_EVENT.SHOW_AWARD, this );
        this._isRegistered = true;
    }
}

protected onDisable(): void
{
    if ( this._isRegistered )
    {
        eventManager.UnRegister( SHOW_AWARD_EVENT.SHOW_AWARD, this );
        this._isRegistered = false;
    }
}

public OnEvent( event: string, ...args: any[] ): void
{
    if ( event !== SHOW_AWARD_EVENT.SHOW_AWARD )
    {
        return;
    }

    const payload = this.ResolveBigWinPayload( args );
    if ( !payload )
    {
        return;
    }

    // 開啟 parentNode
    if ( this.m_parentNode && !this.m_parentNode.active )
    {
        this.m_parentNode.active = true;
    }

    if ( !this.node.active )
    {
        this.node.active = true;
    }

