import { _decorator, Component, Sprite, SpriteFrame } from 'cc';
import { Delegate } from './ExtraType';

const { ccclass, property } = _decorator;

/**@en Frame Animation Controller @zh 逐幀動畫控制器
 * @description Component-based frame-by-frame animation controller @zh 基於組件的逐幀動畫控制器
 */
@ccclass('FrameAnimation')
export class FrameAnimation extends Component {

    //#region Objects
    /**@en Target sprite to display frames @zh 目標顯示幀的Sprite */
    @property({
        type: Sprite,
        tooltip: "顯示動畫幀的Sprite組件"
    })
    private m_sprite: Sprite = null;

    /**@en Animation frames array @zh 動畫幀陣列 */
    @property({
        type: [SpriteFrame],
        tooltip: "動畫幀序列"
    })
    private m_frameSpriteFrames: SpriteFrame[] = [];

    /**@en Animation FPS @zh 動畫幀率 */
    @property({
        tooltip: "動畫播放幀率"
    })
    private m_FPS: number = 30;

    /**@en Is loop animation @zh 是否循環播放 */
    @property({
        tooltip: "是否循環播放動畫"
    })
    private m_isLoop: boolean = true;
    //#endregion

    //#region Properties
    /**@en Animation complete delegate @zh 動畫完成委託 */
    public FinishDelegate: Delegate = new Delegate();

    /**@en Is animation playing @zh 動畫是否正在播放 */
    private m_isPlaying: boolean = false;

    /**@en Is animation paused @zh 動畫是否暫停 */
    private m_isPaused: boolean = false;

    /**@en Current frame index @zh 當前幀索引 */
    private m_frameIndex: number = 0;

    /**@en Total frame count @zh 總幀數 */
    private m_totalFrameAmount: number = 0;

    /**@en Accumulated play time @zh 累積播放時間 */
    private m_playDeltaTime: number = 0;

    /**@en Frame interval time @zh 幀間隔時間 */
    private m_frameRate: number = 0;

    /**@en Component validation cache @zh 組件驗證快取 */
    private m_isComponentsValid: boolean = false;
    //#endregion

    protected onLoad(): void {
        if (this.m_frameSpriteFrames && this.m_frameSpriteFrames.length > 0) {
            this.m_totalFrameAmount = this.m_frameSpriteFrames.length;
        }
        this.m_frameRate = 1.0 / this.m_FPS;

        // 快取組件驗證結果
        this.m_isComponentsValid = this.ValidateComponents();
    }

    protected onDestroy(): void {
        this.ImmediateStop();
        this.m_sprite = null;
        this.m_frameSpriteFrames = [];
        if (this.FinishDelegate) {
            this.FinishDelegate.clear();
            this.FinishDelegate = null;
        }
    }

    protected onDisable(): void {
        this.ImmediateStop();
    }

    protected update(dt: number): void {
        if (!this.m_isPlaying || this.m_isPaused) {
            return;
        }

        this.m_playDeltaTime += dt;

        if (this.m_playDeltaTime >= this.m_frameRate) {
            this.m_playDeltaTime -= this.m_frameRate;

            this.UpdateFrame();

            this.m_frameIndex++;
            if (this.m_frameIndex >= this.m_totalFrameAmount) {
                if (this.m_isLoop) {
                    this.m_frameIndex = 0;
                } else {
                    this.m_isPlaying = false;
                    this.FinishDelegate.notify();
                }
            }
        }
    }

    private UpdateFrame(): void {
        // 使用快取的驗證結果,避免每幀都檢查
        if (!this.m_isComponentsValid) {
            return;
        }

        // 只檢查幀索引範圍(最輕量的檢查)
        if (this.m_frameIndex < 0 || this.m_frameIndex >= this.m_totalFrameAmount) {
            return;
        }

        this.m_sprite.spriteFrame = this.m_frameSpriteFrames[this.m_frameIndex];
    }

    /**@en Play animation from specified index @zh 從指定索引開始播放動畫 */
    public Play(startIndex: number = 0): void {
        // 使用快取的驗證結果
        if (!this.m_isComponentsValid) {
            return;
        }

        this.m_frameIndex = startIndex;
        this.m_isPlaying = true;
        this.m_isPaused = false;
        this.m_playDeltaTime = 0;

        // Display first frame immediately
        this.UpdateFrame();
    }

    /**@en Stop animation @zh 停止動畫 */
    public Stop(): void {
        this.m_isPlaying = false;
        this.m_isPaused = false;
    }

    /**@en Immediate stop animation @zh 立即停止動畫 */
    public ImmediateStop(): void {
        this.m_isPlaying = false;
        this.m_isPaused = false;
        this.m_frameIndex = 0;
        this.m_playDeltaTime = 0;
    }

    /**@en Pause animation @zh 暫停動畫 */
    public Pause(): void {
        if (this.m_isPlaying) {
            this.m_isPaused = true;
        }
    }

    /**@en Resume animation @zh 恢復動畫 */
    public Resume(): void {
        if (this.m_isPlaying) {
            this.m_isPaused = false;
        }
    }

    /**@en Check if animation is playing @zh 檢查動畫是否正在播放 */
    public IsPlaying(): boolean {
        return this.m_isPlaying && !this.m_isPaused;
    }

    /**@en Check if animation is paused @zh 檢查動畫是否暫停 */
    public IsPaused(): boolean {
        return this.m_isPaused;
    }

    /**@en Get current frame index @zh 取得當前幀索引 */
    public GetCurrentFrameIndex(): number {
        return this.m_frameIndex;
    }

    /**@en Get total frame count @zh 取得總幀數 */
    public GetTotalFrameCount(): number {
        return this.m_totalFrameAmount;
    }

    /**@en Set animation FPS @zh 設定動畫幀率 */
    public SetFPS(fps: number): void {
        if (fps > 0) {
            this.m_FPS = fps;
            this.m_frameRate = 1.0 / this.m_FPS;
        }
    }

    /**@en Set loop mode @zh 設定循環模式 */
    public SetLoopMode(isLoop: boolean): void {
        this.m_isLoop = isLoop;
    }

    /**@en Set sprite frames @zh 設定精靈幀 */
    public SetSpriteFrames(frames: SpriteFrame[]): void {
        this.m_frameSpriteFrames = frames;
        this.m_totalFrameAmount = frames ? frames.length : 0;
        // 重新驗證組件
        this.m_isComponentsValid = this.ValidateComponents();
    }

    /**@en Set target sprite @zh 設定目標精靈 */
    public SetTargetSprite(sprite: Sprite): void {
        this.m_sprite = sprite;
        // 重新驗證組件
        this.m_isComponentsValid = this.ValidateComponents();
    }

    private ValidateComponents(): boolean {
        if (!this.m_sprite) {
            console.warn("FrameAnimation: Target sprite is null");
            return false;
        }

        if (!this.m_frameSpriteFrames || this.m_frameSpriteFrames.length === 0) {
            console.warn("FrameAnimation: No sprite frames available");
            return false;
        }

        return true;
    }
}

