/**
 * Timeline Executor — Cocos 3.6.2 整合層
 * 
 * 使用方式：
 * 1. 掛在場景節點上
 * 2. 把所有會用到的 timeline JSON 拖進 timelines 陣列
 *    — targets 會自動根據所有 JSON 的 targetUuid 填入
 * 3. Runtime 呼叫 play(index) 或 playByName(name)
 */
import { _decorator, Component, Node, TextAsset, director, Layers } from "cc";
import { TimelinePlayer, ClipChangeInfo, PlayerCallbacks } from "./TimelinePlayer";
import { TimelineAsset, EventAction, EventData, TrackData, PlayState } from "./TimelineData";

declare const CC_EDITOR: boolean;

const { ccclass, property, executeInEditMode } = _decorator;

/** 序列化用：trackId → targets 陣列的 index */
interface TrackMapping { trackId: string; targetIndex: number; }

@ccclass("TimelineExecutor")
@executeInEditMode
export class TimelineExecutor extends Component {
  @property({ type: [TextAsset] })
  timelines: TextAsset[] = [];

  @property([Node])
  targets: Node[] = [];

  @property({ visible: false })
  private _trackMap: string = "[]"; // JSON string of TrackMapping[]

  private player = new TimelinePlayer();
  private trackNodeMap = new Map<string, Node>();

  onLoad() {
    if (CC_EDITOR) this._autoBindTargets();
  }

  /** 播放第 N 個 timeline */
  play(index: number = 0): void {
    if (index >= this.timelines.length) { console.warn(`[Executor] No timeline at index ${index}`); return; }
    this.playTimeline(JSON.parse(this.timelines[index].text!) as TimelineAsset);
  }

  /** 用 name 播放 */
  playByName(name: string): void {
    for (const t of this.timelines) {
      if (!t) continue;
      const asset = JSON.parse(t.text!) as TimelineAsset;
      if (asset.name === name) { this.playTimeline(asset); return; }
    }
    console.warn(`[Executor] Timeline "${name}" not found`);
  }

  /** 直接傳入 asset 播放 */
  playTimeline(asset: TimelineAsset): void {
    this.buildTrackNodeMap(asset);
    this.player.load(asset, this.buildCallbacks());
    this.registerBuiltinActions();
    this.player.play();
  }

  emitSignal(signalId: string): void { this.player.emitSignal(signalId); }
  stopTimeline(): void { this.player.stop(); }
  onEvent(key: string, handler: (event: EventData) => void): void { this.player.eventBus.on(key, handler); }

  get isPlaying(): boolean { return this.player.state === PlayState.Playing; }

  update(dt: number): void {
    if (this.player.state === PlayState.Playing) {
      this.player.tick(dt);
    }
  }

  // ─── Editor Auto-Bind ──────────────────────────────────────

  private _autoBindTargets(): void {
    const scene = director.getScene() as unknown as Node;
    if (!scene) return;

    const nodeMap = new Map<string, { node: Node; index: number }>(); // uuid → { node, index in targets }
    const newTargets: Node[] = [];
    const mappings: TrackMapping[] = [];

    for (const textAsset of this.timelines) {
      if (!textAsset) continue;
      const asset = JSON.parse(textAsset.text!) as any;
      if (!asset?.tracks) continue;

      for (const track of asset.tracks) {
        const uuid = track.targetUuid;
        if (!uuid) continue;

        // 同一個 uuid 只存一次（多個 track 可能指向同一個節點）
        if (!nodeMap.has(uuid)) {
          const node = this._findByUuid(scene, uuid);
          if (node) {
            const idx = newTargets.length;
            newTargets.push(node);
            nodeMap.set(uuid, { node, index: idx });
          } else {
            console.warn(`[Executor] Auto-bind: uuid "${uuid}" not found (track "${track.id}")`);
            continue;
          }
        }
        mappings.push({ trackId: track.id, targetIndex: nodeMap.get(uuid)!.index });
      }
    }

    this.targets = newTargets;
    this._trackMap = JSON.stringify(mappings);
    console.log(`[Executor] Auto-bound ${newTargets.length} targets, ${mappings.length} track mappings`);
  }

  private _findByUuid(root: Node, uuid: string): Node | null {
    if ((root as any).uuid === uuid) return root;
    for (const child of root.children) {
      const found = this._findByUuid(child, uuid);
      if (found) return found;
    }
    return null;
  }

  // ─── Built-in Event Actions ─────────────────────────────────

  private registerBuiltinActions(): void {
    const actions: EventAction[] = ["change_layer", "set_active", "set_scale", "play_anim"];
    for (const action of actions) {
      this.player.eventBus.onAction(action, (ev) => this.handleEvent(ev));
    }
  }

  /**
   * 內建 action 自動執行。params 約定：
   * - target: trackId (string) 指定目標節點
   * - change_layer: { target, layer: number }
   * - set_active:   { target, active: boolean }
   * - set_scale:    { target, x?, y?, z? } (預設 1)
   * - play_anim:    { target, anim: string, trackIndex?: number, loop?: boolean }
   */
  private handleEvent(ev: EventData): void {
    const node = this.resolveEventTarget(ev);
    if (!node) { console.warn(`[Executor] Event "${ev.key}": target not found`); return; }

    const p = ev.params;
    switch (ev.action) {
      case "change_layer":
        node.layer = (p.layer as number) ?? Layers.Enum.DEFAULT;
        break;
      case "set_active":
        node.active = (p.active as boolean) ?? true;
        break;
      case "set_scale":
        node.setScale(
          (p.x as number) ?? node.scale.x,
          (p.y as number) ?? node.scale.y,
          (p.z as number) ?? node.scale.z,
        );
        break;
      case "play_anim": {
        const skeleton = node.getComponent("sp.Skeleton") as any;
        if (skeleton) {
          skeleton.setAnimation((p.trackIndex as number) ?? 0, p.anim as string, (p.loop as boolean) ?? false);
        } else {
          const anim = node.getComponent("cc.Animation") as any;
          if (anim) anim.play(p.anim as string);
        }
        break;
      }
    }
  }

  private resolveEventTarget(ev: EventData): Node | null {
    const target = ev.params.target as string | number | undefined;
    if (target == null) return null;
    // number → targets 陣列 index
    if (typeof target === "number") return this.targets[target] ?? null;
    // string → 先查 trackId，再查 targetPath
    const byTrack = this.trackNodeMap.get(target);
    if (byTrack) return byTrack;
    // fallback: 遍歷 trackNodeMap 的 node.name 或用 find
    for (const [, node] of this.trackNodeMap) {
      if (node.name === target) return node;
    }
    return null;
  }

  // ─── Runtime ───────────────────────────────────────────────

  private buildTrackNodeMap(asset: TimelineAsset): void {
    this.trackNodeMap.clear();
    const mappings: TrackMapping[] = JSON.parse(this._trackMap || "[]");
    for (const track of asset.tracks) {
      const m = mappings.find((x) => x.trackId === track.id);
      if (m && m.targetIndex < this.targets.length && this.targets[m.targetIndex]) {
        this.trackNodeMap.set(track.id, this.targets[m.targetIndex]);
      }
    }
  }

  private buildCallbacks(): PlayerCallbacks {
    return {
      onClipStart: (info) => this.handleClipStart(info),
      onClipEnd: (info) => this.handleClipEnd(info),
      onFinished: () => this.node.emit("timeline-finished"),
    };
  }

  private handleClipStart(info: ClipChangeInfo): void {
    const targetNode = this.trackNodeMap.get(info.track.id);
    if (!targetNode) { console.warn(`[Executor] No target for track "${info.track.id}"`); return; }

    if (info.track.scriptName) {
      const comp = targetNode.getComponent(info.track.scriptName) as any;
      if (comp && typeof comp.onTimelineClip === "function") {
        comp.onTimelineClip(info.clip.name, info.clip);
      }
    }

    switch (info.track.type) {
      case "spine": {
        const skeleton = targetNode.getComponent("sp.Skeleton") as any;
        if (!skeleton) break;
        skeleton.setAnimation(info.clip.trackIndex ?? 0, info.clip.name, info.clip.loop ?? false);
        if (info.clip.duration === 0) {
          const anim = skeleton.findAnimation?.(info.clip.name);
          if (anim?.duration > 0) info.clip.duration = anim.duration;
        }
        // Forward Spine animation events to eventBus
        skeleton.setEventListener?.((trackEntry: any, event: any) => {
          this.player.eventBus.emit(
            { time: 0, key: event.data?.name || event.name || "", action: "custom", params: { source: "spine", track: info.track.id, event } },
            -1, // index < 0 = no dedup (spine events can fire multiple times)
          );
        });
        break;
      }
      case "node": {
        const anim = targetNode.getComponent("cc.Animation") as any;
        if (anim) anim.play(info.clip.name);
        break;
      }
    }
  }

  private handleClipEnd(info: ClipChangeInfo): void {
    if (info.clip.stopOnEnd && info.track.type === "spine") {
      const targetNode = this.trackNodeMap.get(info.track.id);
      if (targetNode) {
        const skeleton = targetNode.getComponent("sp.Skeleton") as any;
        if (skeleton) { skeleton.clearTrack(info.clip.trackIndex ?? 0); skeleton.setToSetupPose(); }
      }
    }
  }
}

