import { _decorator, Component, Node, Sprite, Camera, RenderTexture, SpriteFrame, log, view, director, UITransform, screen, Widget } from 'cc';
import { Define } from 'db://astarte-framework/utilis/Define';
import { eventManager } from 'db://astarte-framework/Managers';
import Game_Define from "./Game_Define";
import GameView from './GameView';

const { ccclass, property } = _decorator;

export enum RT_EVENT {
    INIT = "INIT",
    CLOSE_RT_CAMERA = "CLOSE_RT_CAMERA",
    AWARD_IN_RT = "AWARD_IN_RT",
    AWARD_OUT_RT = "AWARD_OUT_RT",
}

@ccclass('RTCtrl')  
export class RTCtrl extends Component {

    @property(Sprite)
    sprite: Sprite = null;
    @property(Camera)
    camera: Camera = null;

    @property({ type: [Node], tooltip: '要截圖的節點' })
    private m_hideNodes: Node[] = [];

    @property({ type: Node, tooltip: 'RT Root' })
    private m_RTRoot: Node = null;

    @property({ type: GameView, tooltip: 'GameView' })
    m_gameView: GameView = null;

    protected _renderTex: RenderTexture = null;
    private m_isInAward: boolean = false;

    onLoad(): void {
        this.m_isInAward = false;
        view.on('canvas-resize', this.onCanvasResize, this);
    }

    private onCanvasResize(): void {

        // 鎖定旋轉期間不響應 resize
        if (this.m_gameView.IsLockRotation) return;

        // 延一幀等 Widget 重新計算完
        this.scheduleOnce(() =>
        {
            if(this.m_isInAward)
            {
                this.Init();
                this.AwardOutRT();
            }
            else
            {
                this.Init();
            }
        }, 0.01);
    }

    private RegisterEventListeners(): void {

        eventManager.Register(RT_EVENT.INIT, this);
        eventManager.Register(RT_EVENT.AWARD_IN_RT, this);
        eventManager.Register(RT_EVENT.AWARD_OUT_RT, this);
    }

    private UnregisterEventListeners(): void {

        eventManager.UnRegister(RT_EVENT.INIT, this);
        eventManager.UnRegister(RT_EVENT.AWARD_IN_RT, this);
        eventManager.UnRegister(RT_EVENT.AWARD_OUT_RT, this);
    }

    public async OnEvent(event: string, ...args: any[]): Promise<void> 
    {
        switch (event) {
            case RT_EVENT.INIT:
                this.Init();
                break;
            case RT_EVENT.AWARD_IN_RT:
                await this.AwardInRT();
                break;
            case RT_EVENT.AWARD_OUT_RT:
                this.AwardOutRT();
                break;
        }
    }

    start(): void {
        this.RegisterEventListeners();
    }

    onDestroy(): void {
        this.UnregisterEventListeners();
        view.off('canvas-resize', this.onCanvasResize, this);
        if (this._createdSpriteFrame) {
            this._createdSpriteFrame.destroy();
            this._createdSpriteFrame = null;
        }
        if (this._renderTex) {
            this._renderTex.destroy();
            this._renderTex = null;
        }
    }

    /** @ch 快取的主 Camera 引用 */
    private _cachedMainCamera: Camera = null;

    /** @ch 自己建立的 RT SpriteFrame（不含 prefab 上指定的資產，destroy 才安全） */
    private _createdSpriteFrame: SpriteFrame = null;

    public Init(): void {

        const oldSpriteFrame = this._createdSpriteFrame;
        const oldRenderTex = this._renderTex;

        const sp = new SpriteFrame();
        const renderTex = this._renderTex = new RenderTexture();

        renderTex.reset({
            width: view.getVisibleSize().width,
            height: view.getVisibleSize().height,
        });



        if (!this._cachedMainCamera) {
            const cameras = director.getScene().getComponentsInChildren(Camera);
            this._cachedMainCamera = cameras.find(camera => camera.node.name === 'Camera');
        }
        this.camera.orthoHeight = this._cachedMainCamera.orthoHeight;

        const uiTransform = this.sprite.node.getComponent(UITransform);
        uiTransform.width = view.getVisibleSize().width;
        uiTransform.height = view.getVisibleSize().height;


        this.sprite.node.setPosition(
            0,
            -this.m_gameView.node.position.y,
            0
        );

        this.camera.node.setPosition(
            0,
            -this.m_gameView.node.position.y,
            0
        );



        this.camera.targetTexture = renderTex;
        sp.texture = renderTex;
        this.sprite.spriteFrame = sp;
        this._createdSpriteFrame = sp;

        // 釋放上一次 Init 建立的 RT 資源，防 resize 反覆觸發時洩漏
        if (oldSpriteFrame) {
            oldSpriteFrame.destroy();
        }
        if (oldRenderTex) {
            oldRenderTex.destroy();
        }
    }



    public CloseRTCamera(): void {
        this.camera.node.active = false;
    }


    public async AwardInRT(): Promise<void> {

        this.m_isInAward = true;
        this.m_gameView.IsLockRotation = true;
        // 先激活 RT Root（sprite），讓它經過一幀初始化
        this.m_RTRoot.active = true;
        this.sprite.node.active = false;
        //以防位置沒同步到再做一次
        this.sprite.node.setPosition(
            0,
            -this.m_gameView.node.position.y,
            0
        );

        this.camera.node.setPosition(
            0,
            -this.m_gameView.node.position.y,
            0
        );


        // 開 camera 渲染多幀確保 RT texture 完整
        this.camera.node.active = true;
        await Define.Wait(this, 0.01);
        // 先關 camera 凍結 RT texture（保留完整畫面）
        this.camera.node.active = false;
        this.sprite.node.active = true;
        // 再關物件（RT sprite 已蓋住，不會閃）
        this.m_hideNodes.forEach(node => {
            node.active = false;
        });
        return Promise.resolve();
    }

    public AwardOutRT(): void {
        this.m_isInAward = false;
        this.m_gameView.IsLockRotation = false;
        this.m_hideNodes.forEach(node => {
            node.active = true;
        });
        this.m_RTRoot.active = false;
        this.camera.node.active = true;
    }
}

