StopSymbolWin() {
    this.ReturnAll();
    this.m_gameView.SlotReels.SetSymbolDark(false, -1);
    this.SetReelBlackMaskShow(false);
    this.m_gameView.SlotReels.ShowPlate();
}

async SymbolWinEffect(awardDataVec: protocol.ar2pq9Proto.IAwardData[], keepDark: boolean = false)
{
    const promises = this._reusablePromises;
    promises.length = 0;
    // 配合音效做加速
    let speed = this.m_gameView.IsHardStop ? 2 : 1;

    // 預建贏分位置 Set（避免歸還 scatter 時開靜態 symbol 又馬上被關掉造成閃爍）
    const eliminateSet = this._eliminateSet;
    eliminateSet.clear();
    for (const awardData of awardDataVec) {
        if (awardData.EliminatePos) {
            for (const pos of awardData.EliminatePos) eliminateSet.add(pos);
        }
    }

    // 壓暗全部 symbol
    this.SetReelBlackMaskShow(true);
    // symbol win 演出時歸還標靶和 Scatter 到 pool（下次停輪重建）
    for (const [position, info] of this.m_targetStopNodes) {
        if (info?.node) {
            info.node.active = false;
            PrefabPoolManager.GetInstance().ReturnNode(info.prefabKey, info.node);
        }
        this.m_targetStopNodes.delete(position);
    }
    for (const [position, spine] of this.m_scatterAnimationSpines) {
        if (spine?.node) {
            const prefabKey = spine.node['_prefabKey'];
            spine.node.active = false;
            if (prefabKey) {
                PrefabPoolManager.GetInstance().ReturnNode(prefabKey, spine.node);
            } else {
                spine.node.removeFromParent();
            }
        }
        // 贏分位置跳過（接下來馬上會被 EliminatePos 隱藏+特效蓋住）
        if (!eliminateSet.has(position)) {
            const col = Math.floor(position / Game_Define.ROW);
            const row = position % Game_Define.ROW;
            this.m_gameView.SlotReels.SetSymbolShow(col, row, true);
        }
        this.m_scatterAnimationSpines.delete(position);
    }
    // 贏分位置：隱藏原始 symbol（特效會蓋上去）
    for ( let awardData of awardDataVec )
    {
        let posVec = awardData.EliminatePos;
        for ( let pos of posVec )
        {
            let col = Math.floor( pos / Game_Define.ROW );
            let row = pos % Game_Define.ROW;
            this.m_gameView.SlotReels.SetSymbolShow(col, row, false);
        }
    }

    // 取當前 plate 的盤面資料判斷 Wild
    const curPlateSymbol = this.m_gameView.SpinAck
        .RoundQueue[ this.m_gameView.CurRoundIndex ]
        .PlateQueue[ this.m_gameView.CurPlateIndex ]?.PlateSymbol;
    let pendingEffectNodes = this._pendingEffectNodes;
    pendingEffectNodes.length = 0;
    const playedPosSet = this._playedPosSet;
    playedPosSet.clear();
    const playedNodes = this._playedNodes;
    playedNodes.clear();
    for ( let awardData of awardDataVec )
    {
        let symbol = awardData.Symbol ? awardData.Symbol : 0;
        let posVec = awardData.EliminatePos;
        for ( let pos of posVec )
        {
            if (playedPosSet.has(pos)) continue;
            playedPosSet.add(pos);

            let col = Math.floor( pos / Game_Define.ROW );
            let row = pos % Game_Define.ROW;
            // Wild symbol 播 Wild 自己的贏分動畫
            let actualSymbol = (curPlateSymbol && curPlateSymbol[col]?.Col?.[row]) ?? symbol;
            let isWild = actualSymbol === Game_Define.Symbol.Wild && symbol !== Game_Define.Symbol.Wild;
            let useSymbol = isWild ? Game_Define.Symbol.Wild : symbol;

            let symbolNode = this.CreateEffectNode_NodePool(col, row, Game_Define.LAYERS.SYMBOL, useSymbol);
            // 同一個 spine node 已在本次播放中（pool 命中回傳同一實例）→ 跳過，避免第二次 PlayAnim 的 clearTrack 卡死
            if (playedNodes.has(symbolNode)) continue;
            playedNodes.add(symbolNode);
            let symbolSpine = symbolNode.getComponent( SymbolSpine );
            promises.push( new Promise<void>(
                ( resolve ) =>
                {
                    let settled = false;
                    let guard: any;
                    const settle = () => {
                        if (settled) return;
                        settled = true;
                        clearTimeout(guard);
                        if (keepDark) {
                            // 保留在場上，記錄供後續清除
                            pendingEffectNodes.push({ node: symbolNode, col, row });
                        } else {
                            symbolNode.active = false;
                            this.SetSymbolShow(col, row, true);
                        }
                        resolve();
                    };
                    // 安全 timeout：Wild 等共用 spine track 時，第二次 PlayAnimation 的 clearTrack 可能清掉前者
                    // complete listener，導致此 PlayAnim 永不 resolve 卡死整個 win 演出（speed=1 較慢時更容易發生）。
                    // 逾時強制收尾並 log 卡住的格子，避免凍結。
                    guard = setTimeout(() => {
                        warn(`[SymbolWinEffect] PlayAnim 逾時未 resolve pos=${pos} useSymbol=${useSymbol} node=${symbolNode.name} speed=${speed}`);
                        settle();
                    }, 3000);
                    symbolSpine.SetTimeScale( speed );
                    symbolSpine.SetAnimKey("Win");
                    symbolSpine.PlayAnim().then(settle, settle);
                }
            ) );
        }
    }
    await Promise.all( promises );

    // keepDark 模式：暫存待清除節點（slice 複製，因 _pendingEffectNodes 是共用陣列）
    if (keepDark) {
        this.m_pendingWinEffectNodes = pendingEffectNodes.slice();
    }

    // 解暗（keepDark 時由呼叫方自行解暗）
    if (!keepDark) {
        this.SetReelBlackMaskShow(false);
        // NearWin 時重建盤面上的 Scatter 並播 NearWin 動畫
        this.RebuildScatterSpines();
    }

}

/**
 * @ch 標靶爆炸演出（Symbol_10 Stop→Active，再播 Target_Explode Active_Red/Active_Gold）
 * @param targetDataVec 標靶資料（只播標靶位置的動畫）
 * @param isExpanded 是否為 5x5 強化版（true=金標靶 Active_Gold, false=普通標靶 Active_Red）
 */
async PlayTargetExplodeEffect(targetDataVec: protocol.ar2pq9Proto.ITargetData[], isExpanded: boolean): Promise<void> {
    if (targetDataVec.length === 0) return;

    const symbolPrefabKey = isExpanded ? TARGET_SYMBOL_GOLD_PREFAB_KEY : TARGET_SYMBOL_PREFAB_KEY;
    const explodeAnimName = isExpanded ? "Active_Gold" : "Active_Red";

    for (const targetData of targetDataVec) {
        const pos = targetData.Pos;
        const col = Math.floor(pos / Game_Define.ROW);
        const row = pos % Game_Define.ROW;
