 * @ch 取得所有 Scatter 動畫 Spine 的 map
 */
GetAllScatterAnimationSpines(): Map<number, BaseSpine> {
    return this.m_scatterAnimationSpines;
}

/**@ch 檢查某個 Spine 是否還在 map 中（值比對）*/
HasScatterSpineInMap(spine: BaseSpine): boolean {
    for (const [_, s] of this.m_scatterAnimationSpines) {
        if (s === spine) return true;
    }
    return false;
}

/**@ch 用暫時 key 把 Spine 加回 map（RebuildScatterAnimationSpinesKeys 會修正 key）*/
AddScatterSpineToMap(spine: BaseSpine) {
    // 用負數遞減 key 避免衝突
    let tempKey = -1;
    while (this.m_scatterAnimationSpines.has(tempKey)) tempKey--;
    this.m_scatterAnimationSpines.set(tempKey, spine);
}

/**
 * @ch 根據 Scatter 特效節點的當前世界座標重建 map key
 */
RebuildScatterAnimationSpinesKeys() {
    const newMap = new Map<number, BaseSpine>();
    for (const [_, spine] of this.m_scatterAnimationSpines) {
        if (spine && spine.node.active) {
            const worldPos = spine.node.getWorldPosition();
            // 找最近的格子位置
            for (let col = 0; col < Game_Define.COL; col++) {
                const visibleCount = this.m_gameView.SlotReels.GetVisibleSymbolCount(col);
                for (let row = 0; row < visibleCount; row++) {
                    const cellPos = this.GetSymbolNodeWorldPos(col, row);
                    if (Math.abs(cellPos.x - worldPos.x) < 30 && Math.abs(cellPos.y - worldPos.y) < 30) {
                        const newKey = Common.GetPositionFromColRow(col, row);
                        newMap.set(newKey, spine);
                    }
                }
            }
        }
    }
    this.m_scatterAnimationSpines = newMap;
}

/**@ch 把所有 Scatter Spine 的世界座標校正到對應 symbol 的實際位置（消除累積偏差）*/
SnapScatterSpinesToGrid() {
    for (const [position, spine] of this.m_scatterAnimationSpines) {
        if (spine && spine.node.active) {
            const { col, row } = Common.GetColRowFromPosition(position);
            // 用 EmptyNode 的固定世界座標（避免 symbolNode bounce 中的偏移）
            const targetWorldPos = this.GetSymbolNodeWorldPos(col, row);
            spine.node.setWorldPosition(targetWorldPos);
        }
    }
}

/**
 * @ch 在指定位置建立 Scatter spine 並直接凍結在 Stop 最後一格（不播放、不 loop）
 * （達 5 顆上限後，RebuildScatterSpines 用此取代 NearWin Enter loop）
 */
ShowScatterStopFrozen(col: number, row: number) {
    const position = Common.GetPositionFromColRow(col, row);
    let scatterSpine = this.m_scatterAnimationSpines.get(position);
    if (!scatterSpine) {
        const node = PrefabPoolManager.GetInstance().GetNode(SCATTER_ANIMATION_PREFAB_KEY0);
        if (!node) return;
        node['_prefabKey'] = SCATTER_ANIMATION_PREFAB_KEY0;
        scatterSpine = node.getComponent(BaseSpine);
        if (!scatterSpine) {
            PrefabPoolManager.GetInstance().ReturnNode(SCATTER_ANIMATION_PREFAB_KEY0, node);
            return;
        }
        node.setParent(this.m_effectNodes[Game_Define.LAYERS.SYMBOL]);
        this.m_scatterAnimationSpines.set(position, scatterSpine);
    }
    scatterSpine.node.setWorldPosition(this.GetSymbolNodeWorldPos(col, row));
    scatterSpine.node.active = true;
    const spine = scatterSpine.node.getComponentInChildren(sp.Skeleton);
    if (!spine) return;
    spine.enabled = true;
    const track = spine.setAnimation(0, SCATTER_STOP_ANIMATION_SPINE_KEY, false);
    if (track) track.trackTime = track.animationEnd; // 直接跳到最後一格凍結，不重播
    spine.updateAnimation(0);
}

/**
 * @ch 把所有 Scatter spine 從 Enter loop 切回 Stop 並凍結在最後一格
 * （達 5 顆上限後，場上 scatter 不再 loop，停在 Stop 姿勢；符號維持隱藏由 spine 蓋著）
 */
FreezeAllScattersToStop() {
    for (const [, scatterSpine] of this.m_scatterAnimationSpines) {
        if (!scatterSpine || !scatterSpine.node || !scatterSpine.node.isValid) continue;
        const spine = scatterSpine.node.getComponentInChildren(sp.Skeleton);
        if (!spine) continue;
        spine.enabled = true;
        const track = spine.setAnimation(0, SCATTER_STOP_ANIMATION_SPINE_KEY, false);
        if (track) track.trackTime = track.animationEnd; // 直接跳到最後一格凍結，不重播 Stop
        spine.updateAnimation(0);
    }
}

/**
 * @ch 設定所有場上 Scatter spine 的顯示/隱藏（不銷毀、不歸還）
 */
SetScatterSpinesVisible(visible: boolean) {
    for (const [, scatterSpine] of this.m_scatterAnimationSpines) {
        if (scatterSpine && scatterSpine.node && scatterSpine.node.isValid) {
            scatterSpine.node.active = visible;
        }
    }
}

/**
 * @ch 設定所有場上 Target spine 的顯示/隱藏（不銷毀、不歸還）
 */
SetTargetSpinesVisible(visible: boolean) {
    for (const [, info] of this.m_targetStopNodes) {
        if (info && info.node && info.node.isValid) {
            info.node.active = visible;
        }
    }
}

/**
 * @ch 取得指定位置的 Scatter spine（供外部判斷/操作）
 */
GetScatterSpine(position: number): BaseSpine | null {
    return this.m_scatterAnimationSpines.get(position) || null;
}

/**
 * @ch 歸還所有Scatter進入動畫節點
 */
ReturnAllScatterEnterAnimationNodes() {
    for (const [position, scatterSpine] of this.m_scatterAnimationSpines) {
        if (scatterSpine) {
            scatterSpine.Stop();
            const key = scatterSpine.node['_prefabKey'] || SCATTER_ANIMATION_PREFAB_KEY0;
            PrefabPoolManager.GetInstance().ReturnNode(key, scatterSpine.node);
        }
    }
    this.m_scatterAnimationSpines.clear();

    // 防禦性清除：掃描 effect layer 下殘留的 active Scatter 節點
    for (const effectLayer of this.m_effectNodes) {
        if (!effectLayer) continue;
        const children = effectLayer.children;
        for (let i = children.length - 1; i >= 0; i--) {
            const child = children[i];
            if (child.active && child.name.includes("Scatter")) {
                child.active = false;
            }
        }
    }
}

/**
 * @ch 展示Scatter預中獎動畫
 * @param col 列
 */
ShowScatterPreWinAnimation(col: number) {
    // 檢查同 col 是否已有
    if (this.m_scatterPreWinNodes.has(col)) {
        // 同 col 已有：直接激活
        const scatterPreWinNode = this.m_scatterPreWinNodes.get(col);
        if (scatterPreWinNode) {
            scatterPreWinNode.active = true;
        }

