async PlayScatterWinAnimation(level: number, col: number, row: number, isLoop: boolean, onSpineReady?: (spine: BaseSpine) => void) : Promise<void> 
{
    const position = Common.GetPositionFromColRow(col, row);
    let scatterSpine: BaseSpine;

    // 檢查同位置是否已有 Spine
    if (this.m_scatterAnimationSpines.has(position)) {
        scatterSpine = this.m_scatterAnimationSpines.get(position);
        if (scatterSpine && scatterSpine.node['_reparented']) {
            this.m_scatterAnimationSpines.delete(position);
            scatterSpine = null;
        } else if (scatterSpine) {
            // level 不匹配時重建
            const curKey = scatterSpine.node['_prefabKey'] || SCATTER_ANIMATION_PREFAB_KEY0;
            let wantKey = SCATTER_ANIMATION_PREFAB_KEY0;
            if (level === 1) wantKey = SCATTER_ANIMATION_PREFAB_KEY1;
            else if (level >= 2) wantKey = SCATTER_ANIMATION_PREFAB_KEY2;
            if (curKey !== wantKey) {
                scatterSpine.Stop();
                scatterSpine.node.removeFromParent();
                PrefabPoolManager.GetInstance().ReturnNode(curKey, scatterSpine.node);
                this.m_scatterAnimationSpines.delete(position);
                scatterSpine = null;
            } else {
                scatterSpine.Stop();
            }
