//#region Scatter
/**
 * @ch 回收 Scatter spine 節點到池：停掉殘留 tween、清除掉落標記後歸還。
 * 停 tween 同時保證掉落 tween 的 .call()（AddScatterSpineToMap）不會事後把已回收節點加回 map；
 * 清標記避免節點帶著 _reparented 回池，重取時被誤判為殘留態
 */
private RecycleScatterSpine(scatterSpine: BaseSpine): void {
    const node = scatterSpine.node;
    Tween.stopAllByTarget(node);
    delete node['_reparented'];
    scatterSpine.Stop();
    node.removeFromParent();
    const key = node['_prefabKey'] || SCATTER_ANIMATION_PREFAB_KEY0;
    PrefabPoolManager.GetInstance().ReturnNode(key, node);
}

