spine.enabled = true;
spine.setAnimation(0, SCATTER_STOP_ANIMATION_SPINE_KEY, false);
spine.updateAnimation(0);
await new Promise<void>(resolve => {
    let settled = false;
    let guard: any;
    const settle = () => {
        if (settled) return;
        settled = true;
        clearTimeout(guard);
        if (spine.isValid) {
            spine.setCompleteListener(null);
        }
        resolve();
    };
    // 安全逾時：動畫途中節點被歸還池（ReturnNode 會 clearTracks + disable）時
    // complete 永不觸發，逾時強制收尾避免 Promise 懸掛卡住呼叫端演出
    guard = setTimeout(() => {
        warn(`[PlayScatterStopAnimation] complete 逾時未觸發 col=${col} row=${row}`);
        settle();
    }, 3000);
    spine.setCompleteListener(settle);
});

