ReturnAllScatterEnterAnimationNodes() {
    for (const [position, scatterSpine] of this.m_scatterAnimationSpines) {
        if (scatterSpine) {
            scatterSpine.Stop();
            const key = scatterSpine.node['_prefabKey'] || SCATTER_ANIMATION_PREFAB_KEY0;
            PrefabPoolManager.GetInstance().ReturnNode(key, scatterSpine.node);
        }
    }
    this.m_scatterAnimationSpines.clear();

    // 防禦性清除：掃描 effect layer 下殘留的 active Scatter 節點
    for (const effectLayer of this.m_effectNodes) {
        if (!effectLayer) continue;
        const children = effectLayer.children;
        for (let i = children.length - 1; i >= 0; i--) {
            const child = children[i];
            if (child.active && child.name.includes("Scatter")) {
                child.active = false;
            }
        }
    }
}

