1	/**
2	 * Timeline Player — 播放器核心
3	 * 管理時間推進、軌道狀態、clip 切換、signal 等待/恢復。
4	 * 不直接操作 Cocos 節點，透過 callback 通知外部 Executor。
5	 */
6	import type { TimelineAsset, TrackData, TrackState, ClipData, SignalData } from "./TimelineData";
7	import { PlayState } from "./TimelineData";
8	import { TimelineEventBus } from "./TimelineEvent";
9	
10	export interface ClipChangeInfo {
11	  track: TrackData;
12	  clip: ClipData;
13	  clipIndex: number;
14	}
15	
16	export interface PlayerCallbacks {
17	  /** clip 開始播放 */
18	  onClipStart?: (info: ClipChangeInfo) => void;
19	  /** clip 結束 */
20	  onClipEnd?: (info: ClipChangeInfo) => void;
21	  /** timeline 播放完畢 */
22	  onFinished?: () => void;
23	}
24	
25	export class TimelinePlayer {
26	  private asset: TimelineAsset | null = null;
27	  private trackStates: TrackState[] = [];
28	  private elapsed = 0;
29	  private _state = PlayState.Idle;
30	  private callbacks: PlayerCallbacks = {};
31	  private firedSignals = new Set<string>();
32	  readonly eventBus = new TimelineEventBus();
33	
34	  get state(): PlayState { return this._state; }
35	  get currentTime(): number { return this.elapsed; }
36	
37	  /** 取得所有正在等待 signal 的軌道資訊 */
38	  get waitingTracks(): Array<{ trackId: string; waitingSignal: string }> {
39	    return this.trackStates
40	      .filter((ts) => ts.waitingSignal)
41	      .map((ts) => ({ trackId: ts.trackId, waitingSignal: ts.waitingSignal! }));
42	  }
43	
44	  /** 取得所有已定義的 signal（含是否已觸發） */
45	  get signalStatus(): Array<{ id: string; fired: boolean; at?: number }> {
46	    if (!this.asset) return [];
47	    return this.asset.signals.map((s) => ({ id: s.id, fired: this.firedSignals.has(s.id), at: s.at }));
48	  }
49	
50	  /** 載入 timeline 資料 */
51	  load(asset: TimelineAsset, callbacks?: PlayerCallbacks): void {
52	    this.asset = asset;
53	    this.callbacks = callbacks ?? {};
54	    this.reset();
55	  }
56	
57	  /** 開始播放 */
58	  play(): void {
59	    if (!this.asset || this._state === PlayState.Playing) return;
60	    this._state = PlayState.Playing;
61	    // 觸發所有軌道的第一個 clip
62	    for (const ts of this.trackStates) {
63	      this.startClip(ts);
64	    }
65	  }
66	
67	  /** 暫停 */
68	  pause(): void {
69	    if (this._state === PlayState.Playing) this._state = PlayState.Paused;
70	  }
71	
72	  /** 恢復 */
73	  resume(): void {
74	    if (this._state === PlayState.Paused) this._state = PlayState.Playing;
75	  }
76	
77	  /** 停止並重置 */
78	  stop(): void {
79	    this._state = PlayState.Idle;
80	    this.reset();
81	  }
82	
83	  /** 外部發送 signal（解除等待中的軌道） */
84	  emitSignal(signalId: string): void {
85	    for (const ts of this.trackStates) {
86	      if (ts.waitingSignal === signalId) {
87	        ts.waitingSignal = undefined;
88	        ts.paused = false;
89	        this.advanceTrack(ts);
90	      }
91	    }
92	  }
93	
94	  /** 每幀呼叫（dt 秒） */
95	  tick(dt: number): void {
96	    if (this._state !== PlayState.Playing || !this.asset) return;
97	
98	    this.elapsed += dt;
99	
100	    // 檢查 time-based signals（防重複）
101	    for (const sig of this.asset.signals) {
102	      if (sig.at != null && this.elapsed >= sig.at && !this.firedSignals.has(sig.id)) {
103	        this.firedSignals.add(sig.id);
104	        this.emitSignal(sig.id);
105	      }
106	    }
107	
108	    // 檢查事件觸發
109	    for (let i = 0; i < this.asset.events.length; i++) {
110	      const ev = this.asset.events[i];
111	      if (this.elapsed >= ev.time) {
112	        this.eventBus.emit(ev, i);
113	      }
114	    }
115	
116	    // 推進各軌道
117	    let allFinished = true;
118	    for (const ts of this.trackStates) {
119	      if (ts.paused) { allFinished = false; continue; }
120	      const track = this.getTrack(ts.trackId);
121	      if (!track) continue;
122	      const clip = track.clips[ts.currentClipIndex];
123	      if (!clip) continue; // 軌道已結束
124	
125	      ts.clipElapsed += dt;
126	
127	      if (clip.duration > 0 && ts.clipElapsed >= clip.duration) {
128	        // clip 結束
129	        this.callbacks.onClipEnd?.({ track, clip, clipIndex: ts.currentClipIndex });
130	        this.advanceTrack(ts);
131	      }
132	
133	      if (ts.currentClipIndex < track.clips.length) allFinished = false;
134	    }
135	
136	    if (allFinished) {
137	      this._state = PlayState.Finished;
138	      this.callbacks.onFinished?.();
139	    }
140	  }
141	
142	  // ─── Private ───────────────────────────────────────────────
143	
144	  private reset(): void {
145	    this.elapsed = 0;
146	    this.eventBus.reset();
147	    this.firedSignals.clear();
148	    if (!this.asset) { this.trackStates = []; return; }
149	    this.trackStates = this.asset.tracks.map((t) => ({
150	      trackId: t.id,
151	      currentClipIndex: 0,
152	      clipElapsed: 0,
153	      paused: false,
154	    }));
155	  }
156	
157	  private getTrack(id: string): TrackData | undefined {
158	    return this.asset?.tracks.find((t) => t.id === id);
