}

/**
 * 貝茲曲線移動動畫（本地座標版本，新版）
 * - 回傳可操作的 tween 與可 await 的 done Promise
 * - 不自動 .start()，由呼叫端決定何時開始
 */
static BezierMoveToLocalPositionWithTween(
    flyNode: Node,
    startLocalPosition: Vec3,
    endLocalPosition: Vec3,
    duration: number,
    callback?: () => void
): { tween: Tween<{ progress: number }> | null; done: Promise<void> } {
    let resolveDone: () => void;
    const done = new Promise<void>((resolve) => { resolveDone = resolve; });

    if (!flyNode || !flyNode.isValid) {
        console.warn("BezierMoveToLocalPositionWithTween: flyNode is null or invalid");
        if (callback) callback();
        resolveDone();
        return { tween: null, done };
    }

    // 計算控制點（在起始點和結束點之間的上方創建一個弧形路徑）
    const midX = (startLocalPosition.x + endLocalPosition.x) / 2;
    const midY = (startLocalPosition.y + endLocalPosition.y) / 2;

    // 計算高度偏移：基於起始點和結束點之間的距離
    const distance = Vec3.distance(startLocalPosition, endLocalPosition);
    const heightOffset = Math.max(100, distance * 0.3); // 最小100像素高度

    const controlPoint = new Vec3(midX, midY + heightOffset, 0);

    // 建立貝茲曲線物件（3階貝茲曲線：起始點、控制點、結束點）
    const bezierCurve = new CommonEffect.Bezier([startLocalPosition, controlPoint, endLocalPosition]);

    // 設定起始位置
    flyNode.setPosition(startLocalPosition);

    // 使用臨時物件追蹤動畫進度
    const animationTarget = { progress: 0 };
    const tw = tween(animationTarget)
        .to(duration, { progress: 1 }, {
            onUpdate: (target, ratio) => {
                const currentPos = bezierCurve.GetPosition(ratio);
                flyNode.setPosition(currentPos);
            }
        })
        .call(() => {
            flyNode.setPosition(endLocalPosition);
            if (callback) {
                callback();
            }
            resolveDone();
        });

    return { tween: tw, done };
}

