// scripts/AsyncUtils.ts

import { director, Director, Component, Node } from 'cc';

/**
 * AsyncUtils 非同步工具函式庫
 * 提供與 Cocos Creator 引擎生命週期整合的非同步操作
 * 
 * ===== 基本使用範例 =====
 * 
 * // 1. 等待指定秒數
 * await WaitForSeconds(1.5);  // 等待 1.5 秒
 * 
 * // 2. 等待條件滿足
 * let isAnimationFinished = false;
 * spine.setCompleteListener(() => isAnimationFinished = true);
 * await WaitUntil(() => isAnimationFinished);  // 等待動畫完成
 * 
 * // 3. 等待指定幀數
 * await WaitFrames(30);  // 等待 30 幀（約 0.5 秒 @60fps）
 * 
 * // 4. 等待下一幀
 * await WaitNextFrame();  // 等待下一個渲染幀
 * 
 * ===== CancelToken 進階使用範例 =====
 * 
 * // 創建取消控制器
 * const cancelToken = CreateCancelToken();
 * 
 * // 在另一個地方取消操作（使用 Cocos 調度器）
 * const scheduler = SchedulerManager.getInstance();
 * scheduler.scheduleOnce(() => {
 *     cancelToken.isCancelled = true;  // 3 秒後取消
 * }, 3);
 * 
 * // 使用取消控制器
 * try {
 *     await WaitForSeconds(5, cancelToken);  // 等待 5 秒，但可能被提前取消
 *     console.log("正常完成");
 * } catch (error) {
 *     console.log("被取消了");
 * }
 * 
 * ===== 遊戲場景實際應用範例 =====
 * 
 * // 範例 1: 等待玩家點擊確認
 * class GameState {
 *     async WaitForPlayerConfirm(): Promise<void> {
 *         let isConfirmed = false;
 *         const cancelToken = CreateCancelToken();
 *         
 *         // 設定 10 秒超時（使用 Cocos 調度器）
 *         const scheduler = SchedulerManager.getInstance();
 *         scheduler.scheduleOnce(() => cancelToken.isCancelled = true, 10);
 *         
 *         // 監聽點擊事件
 *         this.confirmButton.on('click', () => isConfirmed = true);
 *         
 *         // 等待確認或超時
 *         await WaitUntil(() => isConfirmed, cancelToken);
 *     }
 * }
 * 
 * // 範例 2: 免費遊戲結束等待大獎動畫
 * class LeaveFreeState {
 *     async PlayFreeGameTotalWinAward(): Promise<void> {
 *         let isPlayAward = true;
 *         const cancelToken = CreateCancelToken();
 *         
 *         // 播放大獎動畫，完成時設定標誌
 *         this.gameView.ShowBigWin(totalWin, winType, () => {
 *             isPlayAward = false;
 *         });
 *         
 *         // 等待動畫完成，支援玩家點擊跳過
 *         this.skipButton.on('click', () => cancelToken.isCancelled = true);
 *         await WaitUntil(() => !isPlayAward, cancelToken);
 *     }
 * }
 * 
 * // 範例 3: 轉輪停止序列
 * class SpinController {
 *     async StopReelsSequentially(): Promise<void> {
 *         const cancelToken = CreateCancelToken();
 *         
 *         // 如果玩家按下快速停止，取消延遲
 *         this.quickStopButton.on('click', () => cancelToken.isCancelled = true);
 *         
 *         for (let i = 0; i < 5; i++) {
 *             this.stopReel(i);
 *             await WaitForSeconds(0.2, cancelToken);  // 每個轉輪間隔 0.2 秒停止
 *         }
 *     }
 * }
 * 
 * ===== 注意事項 =====
 * 
 * 1. 所有函式都使用 Cocos Creator 的調度器系統，與引擎生命週期同步
 * 2. CancelToken 是簡單的物件，設定 isCancelled = true 即可取消
 * 3. 被取消的 Promise 會立即 resolve，不會拋出例外
 * 4. 在場景切換時，調度器會自動清理，避免記憶體洩漏
 * 5. 使用 await 語法時，確保函式標記為 async
 */

export type CancelToken = { isCancelled: boolean };

/**
 * 內部調度器管理器
 * 用於管理 Cocos 調度器的實例
 */
class SchedulerManager {
    private static m_instance: SchedulerManager;
    private m_dummyComponent: Component;

    private constructor() {
        // 創建一個虛擬的 Node 和 Component 用於調度
        const dummyNode = new Node('AsyncUtilsScheduler');
        this.m_dummyComponent = dummyNode.addComponent(Component);
        // 將節點添加到場景中，但設為持久化
        director.getScene()?.addChild(dummyNode);
        director.addPersistRootNode(dummyNode);
    }

    public static getInstance(): SchedulerManager {
        if (!SchedulerManager.m_instance) {
            SchedulerManager.m_instance = new SchedulerManager();
        }
        return SchedulerManager.m_instance;
    }

    public scheduleOnce(callback: () => void, delay: number): void {
        this.m_dummyComponent.scheduleOnce(callback, delay);
    }

    public unschedule(callback: () => void): void {
        this.m_dummyComponent.unschedule(callback);
    }
}

/**
 * 等待指定秒數（非阻塞）
 * 使用 Cocos Creator 的調度器系統，與引擎生命週期同步
 * @param seconds 秒數（例如 1.5）
 * @param cancelToken 可選的取消控制
 */
export function WaitForSeconds(seconds: number, cancelToken?: CancelToken): Promise<void> {
    return new Promise(resolve => {
        let isResolved = false;
        const scheduler = SchedulerManager.getInstance();

        // 創建延遲回調函數
        const delayCallback = () => {
            if (!cancelToken?.isCancelled && !isResolved) {
                isResolved = true;
                resolve();
            }
        };

        // 使用 Cocos 調度器
        scheduler.scheduleOnce(delayCallback, seconds);

        // 如果有取消控制，使用 frame 檢查
        if (cancelToken) {
            const cancelCheck = () => {
                if (cancelToken.isCancelled) {
                    if (!isResolved) {
                        scheduler.unschedule(delayCallback);
                        isResolved = true;
                        resolve();
                    }
                } else if (!isResolved) {
                    // 使用 director 的下一幀事件繼續檢查
                    director.once(Director.EVENT_AFTER_UPDATE, cancelCheck);
                }
            };
            cancelCheck();
        }
    });
}

/**
 * 每 frame 檢查條件直到為 true 為止
 * @param condition 條件函式
 * @param cancelToken 可選的取消控制
 */
export function WaitUntil(condition: () => boolean, cancelToken?: CancelToken): Promise<void> {
    return new Promise(resolve => {
        function check() {
            if (cancelToken?.isCancelled) { resolve(); return; }
            if (condition()) {
                resolve();
            } else {
                director.once(Director.EVENT_AFTER_UPDATE, check);
            }
        }
        check();
    });
}

/**
 * 每 frame 檢查條件直到為 false 為止
 */
export function WaitWhile(condition: () => boolean, cancelToken?: CancelToken): Promise<void> {
    return WaitUntil(() => !condition(), cancelToken);
}

/**
 * 等待下一個 frame
 */
export function WaitNextFrame(cancelToken?: CancelToken): Promise<void> {
    return new Promise(resolve => {
        if (cancelToken?.isCancelled) { resolve(); return; }
        director.once(Director.EVENT_AFTER_UPDATE, () => {
            if (cancelToken?.isCancelled) { resolve(); return; }
            resolve();
        });
    });
}

/**
 * 等待指定 frame 數
 */
export function WaitFrames(frameCount: number, cancelToken?: CancelToken): Promise<void> {
    return new Promise(resolve => {
        let count = 0;
        function next() {
            if (cancelToken?.isCancelled) { resolve(); return; }
            count++;
            if (count >= frameCount) {
                resolve();
            } else {
                director.once(Director.EVENT_AFTER_UPDATE, next);
            }
        }
        next();
    });
}

/**
 * 建立取消控制器
 */
export function CreateCancelToken(): CancelToken {
    return { isCancelled: false };
}

