/**
 * 內部調度器管理器
 * 用於管理 Cocos 調度器的實例
 */
class SchedulerManager {
    private static m_instance: SchedulerManager;
    private m_dummyComponent: Component;

    private constructor() {
        // 創建一個虛擬的 Node 和 Component 用於調度
        const dummyNode = new Node('AsyncUtilsScheduler');
