                scheduler.unschedule(cancelCheck);
                scheduler.unschedule(delayCallback);
                if (!isResolved) {
                    isResolved = true;
                    resolve();
                }
            }
        };

        if (cancelToken?.isCancelled) {
            isResolved = true;
            resolve();
            return;
        }

        // 使用 Cocos 調度器
        scheduler.scheduleOnce(delayCallback, seconds);

        if (cancelToken) {
            scheduler.schedule(cancelCheck);
        }
    });
}

