toolUseResult.originalFile:
/**
 * Timeline Player — 播放器核心
 * 管理時間推進、軌道狀態、clip 切換、signal 等待/恢復。
 * 不直接操作 Cocos 節點，透過 callback 通知外部 Executor。
 */
import type { TimelineAsset, TrackData, TrackState, ClipData, SignalData } from "./TimelineData";
import { PlayState } from "./TimelineData";
import { TimelineEventBus } from "./TimelineEvent";

export interface ClipChangeInfo {
  track: TrackData;
  clip: ClipData;
  clipIndex: number;
}

export interface PlayerCallbacks {
  /** clip 開始播放 */
  onClipStart?: (info: ClipChangeInfo) => void;
  /** clip 結束 */
  onClipEnd?: (info: ClipChangeInfo) => void;
  /** timeline 播放完畢 */
  onFinished?: () => void;
}

export class TimelinePlayer {
  private asset: TimelineAsset | null = null;
  private trackStates: TrackState[] = [];
  private elapsed = 0;
  private _state = PlayState.Idle;
  private callbacks: PlayerCallbacks = {};
  private firedSignals = new Set<string>();
  readonly eventBus = new TimelineEventBus();

  get state(): PlayState { return this._state; }
  get currentTime(): number { return this.elapsed; }

  /** 取得所有正在等待 signal 的軌道資訊 */
  get waitingTracks(): Array<{ trackId: string; waitingSignal: string }> {
    return this.trackStates
      .filter((ts) => ts.waitingSignal)
      .map((ts) => ({ trackId: ts.trackId, waitingSignal: ts.waitingSignal! }));
  }

  /** 取得所有已定義的 signal（含是否已觸發） */
  get signalStatus(): Array<{ id: string; fired: boolean; at?: number }> {
    if (!this.asset) return [];
    return this.asset.signals.map((s) => ({ id: s.id, fired: this.firedSignals.has(s.id), at: s.at }));
  }

  /** 載入 timeline 資料 */
  load(asset: TimelineAsset, callbacks?: PlayerCallbacks): void {
    this.asset = asset;
    this.callbacks = callbacks ?? {};
    this.reset();
  }

  /** 開始播放 */
  play(): void {
    if (!this.asset || this._state === PlayState.Playing) return;
    this._state = PlayState.Playing;
    // 觸發所有軌道的第一個 clip
    for (const ts of this.trackStates) {
      this.startClip(ts);
    }
  }

  /** 暫停 */
  pause(): void {
    if (this._state === PlayState.Playing) this._state = PlayState.Paused;
  }

  /** 恢復 */
  resume(): void {
    if (this._state === PlayState.Paused) this._state = PlayState.Playing;
  }

  /** 停止並重置 */
  stop(): void {
    this._state = PlayState.Idle;
    this.reset();
  }

  /** 外部發送 signal（解除等待中的軌道） */
  emitSignal(signalId: string): void {
    for (const ts of this.trackStates) {
      if (ts.waitingSignal === signalId) {
        ts.waitingSignal = undefined;
        ts.paused = false;
        this.advanceTrack(ts);
      }
    }
  }

  /** 每幀呼叫（dt 秒） */
  tick(dt: number): void {
    if (this._state !== PlayState.Playing || !this.asset) return;

    this.elapsed += dt;

    // 檢查 time-based signals（防重複）
    for (const sig of this.asset.signals) {
      if (sig.at != null && this.elapsed >= sig.at && !this.firedSignals.has(sig.id)) {
        this.firedSignals.add(sig.id);
        this.emitSignal(sig.id);
      }
    }

    // 檢查事件觸發
    for (let i = 0; i < this.asset.events.length; i++) {
      const ev = this.asset.events[i];
      if (this.elapsed >= ev.time) {
        this.eventBus.emit(ev, i);
      }
    }

    // 推進各軌道
    let allFinished = true;
    for (const ts of this.trackStates) {
      if (ts.paused) { allFinished = false; continue; }
      const track = this.getTrack(ts.trackId);
      if (!track) continue;
      const clip = track.clips[ts.currentClipIndex];
      if (!clip) continue; // 軌道已結束

      ts.clipElapsed += dt;

      if (clip.duration > 0 && ts.clipElapsed >= clip.duration) {
        // clip 結束
        this.callbacks.onClipEnd?.({ track, clip, clipIndex: ts.currentClipIndex });
        this.advanceTrack(ts);
      }

      if (ts.currentClipIndex < track.clips.length) allFinished = false;
    }

    if (allFinished) {
      this._state = PlayState.Finished;
      this.callbacks.onFinished?.();
    }
  }

  // ─── Private ───────────────────────────────────────────────

  private reset(): void {
    this.elapsed = 0;
    this.eventBus.reset();
    this.firedSignals.clear();
    if (!this.asset) { this.trackStates = []; return; }
    this.trackStates = this.asset.tracks.map((t) => ({
      trackId: t.id,
      currentClipIndex: 0,
      clipElapsed: 0,
      paused: false,
    }));
  }

  private getTrack(id: string): TrackData | undefined {
    return this.asset?.tracks.find((t) => t.id === id);
  }

  private startClip(ts: TrackState): void {
    const track = this.getTrack(ts.trackId);
    if (!track) return;
    const clip = track.clips[ts.currentClipIndex];
    if (!clip) return;

    // duration=-1 表示等待 signal
    if (clip.duration < 0) {
      ts.paused = true;
      ts.waitingSignal = clip.name; // 預設用 clip name 作為 signal ID
    }

    this.callbacks.onClipStart?.({ track, clip, clipIndex: ts.currentClipIndex });
  }

  private advanceTrack(ts: TrackState): void {
    ts.currentClipIndex++;
    ts.clipElapsed = 0;
    ts.paused = false;
    ts.waitingSignal = undefined;
    this.startClip(ts);
  }
}

