import { _decorator, Component, Label, tween } from 'cc';
import { Delegate } from './ExtraType';

const { ccclass, property } = _decorator;

/**@en Number Animation Controller @ch 數字動畫控制器
 * @description Component-based number rolling animation controller @ch 基於組件的數字滾動動畫控制器
 */
@ccclass('NumberAnimation')
export class NumberAnimation extends Component {
    /**@en Target label to display numbers @ch 目標顯示數字的Label */
    @property({
        type: Label,
        tooltip: "顯示數字的Label"
    })
    private m_targetLabel: Label = null;

    public FinishDelegate: Delegate = new Delegate(); //滾到目標時會呼叫的 Delegate

    /**@en Current tween instance @ch 當前的Tween實例 */
    private m_currentTween: any = null;

    /**@en Format function for number display @ch 數字顯示格式化函數 */
    private m_formatFunction: (value: number) => string = null;

    /**@en Current animation state @ch 當前動畫狀態 */
    private m_isPlaying: boolean = false;

    /**@en Current value @ch 當前數值 */
    private m_currentValue: number = 0;

    /**@en Target value @ch 目標數值 */
    private m_targetValue: number = 0;

    /**@en Animation duration @ch 動畫持續時間 */
    private m_duration: number = 1.0;

    /**@en Is animation paused @ch 動畫是否暫停 */
    private m_isPaused: boolean = false;

    /**@en Current Promise resolver @ch 當前Promise的resolver */
    private m_currentPromiseResolve: (() => void) | null = null;

    protected onLoad(): void {
        // 設定預設格式化函數
        if (!this.m_formatFunction) {
            this.m_formatFunction = this.DefaultFormat;
        }
        this.Reset();
    }

    protected onDestroy(): void {
        this.Stop();
        this.m_targetLabel = null;
        this.m_formatFunction = null;
        this.m_currentPromiseResolve = null;
    }

    /**@en Default number format function @ch 預設數字格式化函數 */
    private DefaultFormat(value: number): string {
        return Math.floor(value).toString();
    }

    /**@en Update label display @ch 更新Label顯示 */
    private UpdateDisplay(value: number): void {
        if (!this.m_targetLabel) {
            console.warn("NumberAnimation: Target label is null");
            return;
        }

        this.m_currentValue = value;
        this.m_targetLabel.string = this.m_formatFunction(value);
    }

    /**@en Set format function @ch 設定格式化函數 */
    public SetFormatFunction(formatFunction: (value: number) => string): void {
        this.m_formatFunction = formatFunction || this.DefaultFormat;
    }

    /**@en Check if animation is playing @ch 檢查動畫是否正在播放 */
    public IsPlaying(): boolean {
        return this.m_isPlaying;
    }

    /**@en Check if animation is paused @ch 檢查動畫是否暫停 */
    public IsPaused(): boolean {
        return this.m_isPaused;
    }

    /**@en Get current value @ch 取得當前數值 */
    public GetCurrentValue(): number {
        return this.m_currentValue;
    }

    /**@en Get target value @ch 取得目標數值 */
    public GetTargetValue(): number {
        return this.m_targetValue;
    }

    /**@en Reset animation state @ch 重置動畫狀態 */
    public Reset(): void {
        this.Stop();
        this.m_currentValue = 0;
        this.m_targetValue = 0;
        this.m_duration = 1.0;
        this.m_isPaused = false;
        this.UpdateDisplay(0);
    }

    /**@en Stop current animation @ch 停止當前動畫 */
    public Stop(): void {
        if (this.m_currentTween) {
            this.m_currentTween.stop();
            this.m_currentTween = null;
        }
        this.m_isPlaying = false;
        this.m_isPaused = false;

        // 清除Promise resolver，避免記憶體洩漏
        if (this.m_currentPromiseResolve) {
            this.m_currentPromiseResolve = null;
        }
    }

    /**@en Pause current animation @ch 暫停當前動畫 */
    public Pause(): void {
        if (this.m_currentTween && this.m_isPlaying && !this.m_isPaused) {
            this.m_currentTween.pauseAllActions();
            this.m_isPaused = true;
        }
    }

    /**@en Resume paused animation @ch 恢復暫停的動畫 */
    public Resume(): void {
        if (this.m_currentTween && this.m_isPlaying && this.m_isPaused) {
            this.m_currentTween.resumeAllActions();
            this.m_isPaused = false;
        }
    }

    /**@en Set target label @ch 設定目標Label */
    public SetTargetLabel(label: Label): void {
        this.m_targetLabel = label;
    }

    /**@en Play number rolling animation @ch 播放數字滾動動畫 */
    public async PlayRolling(from: number, to: number, duration: number = 1.0): Promise<void> {
        if (!this.m_targetLabel) {
            console.warn("NumberAnimation: Target label is null");
            return Promise.resolve();
        }

        // 停止之前的動畫
        this.Stop();

        // 設定狀態
        this.m_isPlaying = true;
        this.m_currentValue = from;
        this.m_targetValue = to;
        this.m_duration = duration;
        this.m_isPaused = false;

        // 初始化顯示
        this.UpdateDisplay(from);

        return new Promise<void>((resolve) => {
            // 儲存resolver以供外部中斷使用
            this.m_currentPromiseResolve = resolve;

            let current = from;

            // 建立數值滾動動畫
            this.m_currentTween = tween({ value: current })
                .to(duration, { value: to }, {
                    onUpdate: (target: any) => {
                        current = target.value;
                        this.UpdateDisplay(current);
                    }
                })
                .call(() => {
                    // 確保最終值是正確的
                    this.UpdateDisplay(to);
                    this.m_currentTween = null;
                    this.m_isPlaying = false;
                    this.m_isPaused = false;

                    // 清除resolver參考
                    this.m_currentPromiseResolve = null;

                    // 調用完成委託
                    this.FinishDelegate.notify();

                    resolve();
                })
                .start();
        });
    }

    /**@en Play rolling from current value @ch 從當前數值開始滾動 */
    public async PlayRollingFromCurrent(to: number, duration: number = 1.0): Promise<void> {
        return this.PlayRolling(this.m_currentValue, to, duration);
    }

    /**@en Set value immediately without animation @ch 立即設定數值不使用動畫 */
    public SetValueImmediate(value: number): void {
        this.Stop();
        this.m_currentValue = value;
        this.m_targetValue = value;
        this.UpdateDisplay(value);

        // 調用完成委託
        this.FinishDelegate.notify();
    }

    /**@en Stop rolling and jump to target value @ch 停止滾動並跳轉到目標值 */
    public StopAndJumpToTarget(): void {
        if (!this.m_isPlaying) {
            return;
        }

        // 停止當前動畫
        if (this.m_currentTween) {
            this.m_currentTween.stop();
            this.m_currentTween = null;
        }

        // 設定為目標值
        this.UpdateDisplay(this.m_targetValue);

        // 重置狀態
        this.m_isPlaying = false;
        this.m_isPaused = false;

        // 調用完成委託
        this.FinishDelegate.notify();

        // 如果有等待中的Promise，主動resolve它
        if (this.m_currentPromiseResolve) {
            this.m_currentPromiseResolve();
            this.m_currentPromiseResolve = null;
        }
    }
}

